        if (shouldAddLogo || mode === 'remove-text' || mode === 'both') {
           processedImages[i].progressMessage = shouldAddLogo ? '正在合成水印...' : '正在优化尺寸...';
           processedImages[i].progressValue = shouldAddLogo ? 60 : 80;
           setImages([...processedImages]);

           try {
              currentResultUrl = await applyLogoToImage(
                  currentResultUrl, 
                  shouldAddLogo ? logoUrl : null, 
                  logoSettings,
                  originalDims
              );
           } catch (err: any) {
              throw new Error(`图像合成失败: ${err.message}`);
           }
        }

        // Finalize
        processedImages[i] = {
          ...img,
          resultUrl: currentResultUrl,
          status: ProcessStatus.COMPLETED,
          progressValue: 100,
          progressMessage: '处理完成'
        };
      } catch (error: any) {
        processedImages[i] = {
          ...img,
          status: ProcessStatus.ERROR,
          errorMessage: error.message,
          progressValue: 0,
          progressMessage: '处理出错'
        };
      }

      // Update state after each image to show progress
      setImages([...processedImages]);
    }

    setIsProcessing(false);
  };

  // Download Handler
  const downloadImage = (img: ProcessedImage) => {
    if (!img.resultUrl) return;
    const link = document.createElement('a');
    link.href = img.resultUrl;
    link.download = `processed_${img.originalFile.name.split('.')[0]}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Download All Handler
  const handleDownloadAll = async () => {
    const completedImages = images.filter(img => img.status === ProcessStatus.COMPLETED && img.resultUrl);
    if (completedImages.length === 0) return;

    setIsZipping(true);
    try {
      const zip = new JSZip();

      const promises = completedImages.map(async (img) => {
        if (!img.resultUrl) return;
        const response = await fetch(img.resultUrl);
        const blob = await response.blob();

        // Determine extension
        let ext = 'png';
        if (blob.type === 'image/jpeg') ext = 'jpg';
        else if (blob.type === 'image/webp') ext = 'webp';

        const originalName = img.originalFile.name;
        const nameWithoutExt = originalName.substring(0, originalName.lastIndexOf('.')) || originalName;

        zip.file(`processed_${nameWithoutExt}.${ext}`, blob);
      });

      await Promise.all(promises);

      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `cleanslate_batch_${new Date().getTime()}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (error) {
      console.error("Zip generation failed", error);
      alert("打包下载失败，请重试");
    } finally {
      setIsZipping(false);
    }
  };

  const clearAll = () => {
    images.forEach(img => {
        URL.revokeObjectURL(img.previewUrl);
        if(img.resultUrl) URL.revokeObjectURL(img.resultUrl);
    });
    setImages([]);
  };

  // Determines the image to show in the logo editor preview
  const firstPreviewImage = useMemo(() => {
    return images.length > 0 ? images[0].previewUrl : null;
  }, [images]);

  const hasCompletedImages = images.some(img => img.status === ProcessStatus.COMPLETED);

  return (
    <div className="flex h-full text-gray-100">
      {/* Sidebar Controls */}
      <aside className="w-80 flex-shrink-0 bg-gray-900 border-r border-gray-800 flex flex-col p-4 space-y-6 overflow-y-auto">
        <div>
          <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text text-transparent flex items-center gap-2">
            <Layers className="w-6 h-6 text-indigo-400" />
            CleanSlate AI
          </h1>
          <p className="text-xs text-gray-500 mt-1">批量去字 & 品牌水印</p>
        </div>

        {/* Mode Selector */}
        <div className="space-y-3">
          <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider">操作模式</label>
          <div className="grid grid-cols-1 gap-2">
            <button
              onClick={() => setMode('remove-text')}
              className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
                mode === 'remove-text'
                  ? 'bg-indigo-900/40 border-indigo-500 text-white'
                  : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'
              }`}
            >
              <Wand2 className="w-5 h-5" />
              <div className="text-left">
                <div className="font-medium">去除文字</div>
                <div className="text-xs opacity-70">AI 智能清除</div>
              </div>
            </button>

            <button
              onClick={() => setMode('add-logo')}
              className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
                mode === 'add-logo'
                  ? 'bg-indigo-900/40 border-indigo-500 text-white'
                  : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'
              }`}
            >
              <Stamp className="w-5 h-5" />
              <div className="text-left">
                <div className="font-medium">添加 Logo</div>
                <div className="text-xs opacity-70">水印布局</div>
              </div>
            </button>

            <button
              onClick={() => setMode('both')}
              className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
                mode === 'both'
                  ? 'bg-indigo-900/40 border-indigo-500 text-white'
                  : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'
              }`}
            >
              <Layers className="w-5 h-5" />
              <div className="text-left">
                <div className="font-medium">去字 & 水印</div>
                <div className="text-xs opacity-70">先去字，后加 Logo</div>
              </div>
            </button>
          </div>
        </div>

        {/* Logo Controls (Only if needed) */}
        {(mode === 'add-logo' || mode === 'both') && (
          <LogoControls
            logoUrl={logoUrl}
            settings={logoSettings}
            onSettingsChange={setLogoSettings}
            onLogoUpload={handleLogoUpload}
            onLogoRemove={() => setLogoUrl(null)}
            previewImageUrl={firstPreviewImage}
          />
        )}

        {/* Action Button */}
        <div className="pt-4 mt-auto">
          <button
            onClick={processBatch}
            disabled={isProcessing || images.length === 0}
            className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-2 transition-all ${
              isProcessing || images.length === 0
                ? 'bg-gray-700 text-gray-500 cursor-not-allowed'
                : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white transform hover:scale-[1.02]'
            }`}
          >
            {isProcessing ? (
              <>
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                处理中...
              </>
            ) : (
              <>
                <Play className="w-5 h-5 fill-current" />
                开始处理
              </>
            )}
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col bg-gray-950 overflow-hidden relative">
        {/* Header / Stats */}
        <header className="h-16 border-b border-gray-800 flex items-center justify-between px-6 bg-gray-900/50 backdrop-blur">
          <div className="flex items-center gap-4">
             <span className="text-gray-400 text-sm">
                已加载 {images.length} 张图片
             </span>
             {hasCompletedImages && (
                <span className="text-green-400 text-sm flex items-center gap-1">
                   <div className="w-2 h-2 rounded-full bg-green-500"></div>
                   准备下载
                </span>
             )}
          </div>
          <div className="flex gap-2">
             {hasCompletedImages && (
                <button 
                    onClick={handleDownloadAll}
                    disabled={isZipping}
                    className="px-3 py-1.5 text-sm bg-indigo-600 hover:bg-indigo-500 disabled:bg-indigo-800 disabled:text-gray-400 text-white rounded-lg transition-colors flex items-center gap-2 shadow-lg shadow-indigo-900/20"
                >
                    {isZipping ? (
                        <>
                           <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                           打包中...
                        </>
                    ) : (
                        <>
                           <Package className="w-4 h-4" /> 批量下载
                        </>
                    )}
                </button>
             )}

             <button 
                onClick={clearAll}
                className="px-3 py-1.5 text-sm text-red-400 hover:bg-red-900/20 rounded-lg transition-colors flex items-center gap-2"
                disabled={isProcessing}
             >
                <Trash2 className="w-4 h-4"/> 清空所有
             </button>
             <label className="cursor-pointer px-4 py-1.5 text-sm bg-gray-700 hover:bg-gray-600 text-white rounded-lg transition-colors flex items-center gap-2">
                <Upload className="w-4 h-4"/> 添加图片
                <input type="file" multiple accept="image/*" onChange={handleImageUpload} className="hidden" />
             </label>
          </div>
        </header>

        {/* Image Grid */}
        <div className="flex-1 overflow-y-auto p-6">
          {images.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-500 border-2 border-dashed border-gray-800 rounded-3xl bg-gray-900/30 m-4">
              <div className="p-8 bg-gray-900 rounded-full mb-6">
                <ImageIcon className="w-12 h-12 text-indigo-500" />
              </div>
              <h2 className="text-2xl font-semibold text-gray-300 mb-2">拖放图片到这里</h2>
              <p className="max-w-md text-center text-gray-500">
                上传多张图片以批量去除文字或添加您的品牌水印。
              </p>
              <label className="mt-8 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl cursor-pointer font-medium transition-transform hover:scale-105">
                选择文件
                <input type="file" multiple accept="image/*" onChange={handleImageUpload} className="hidden" />
              </label>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
              {images.map((img) => (
                <div
                  key={img.id}
                  className="group relative bg-gray-800 rounded-xl overflow-hidden shadow-xl border border-gray-700 hover:border-indigo-500/50 transition-all"
                >
                  {/* Image Preview */}
                  <div className="aspect-video relative bg-gray-900 flex items-center justify-center overflow-hidden">
                    {img.status === ProcessStatus.COMPLETED && img.resultUrl ? (
                         // Compare View
                         <>
                            <img src={img.resultUrl} className="w-full h-full object-contain" alt="Processed" />
                            <div className="absolute top-2 left-2 bg-green-500/90 text-white text-[10px] font-bold px-2 py-0.5 rounded shadow-sm">
                                已处理
                            </div>
                         </>
                    ) : (
                         <img src={img.previewUrl} className={`w-full h-full object-contain ${img.status === ProcessStatus.PROCESSING ? 'opacity-50' : ''}`} alt="Original" />
                    )}

                    {/* Status Overlays */}
                    {img.status === ProcessStatus.PROCESSING && (
                        <div className="absolute inset-0 bg-gray-900/70 backdrop-blur-sm flex flex-col items-center justify-center z-10">
                            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-3"></div>
                            <div className="w-48 bg-gray-700 rounded-full h-2 mb-2 overflow-hidden">
                                <div 
                                   className="bg-indigo-500 h-full transition-all duration-300 ease-out"
                                   style={{ width: `${img.progressValue || 0}%` }}
                                ></div>
                            </div>
                            <span className="text-white text-sm font-medium animate-pulse">{img.progressMessage || '处理中...'}</span>
                        </div>
                    )}

                    {img.status === ProcessStatus.ERROR && (
                        <div className="absolute inset-0 bg-red-900/60 flex flex-col items-center justify-center p-4 text-center">
                            <AlertCircle className="w-8 h-8 text-red-200 mb-2" />
                            <span className="text-red-200 text-xs font-medium">{img.errorMessage}</span>
                        </div>
                    )}
                  </div>

                  {/* Footer Actions */}
                  <div className="p-3 bg-gray-800 flex items-center justify-between border-t border-gray-700">
                    <div className="truncate text-xs text-gray-400 max-w-[150px]">
                        {img.originalFile.name}
                    </div>
                    <div className="flex gap-2">
                         {img.status === ProcessStatus.COMPLETED ? (
                             <button 
                                onClick={() => downloadImage(img)}
                                className="p-2 hover:bg-green-500/20 text-green-400 rounded-lg transition-colors"
                                title="下载"
                             >
                                <Download className="w-4 h-4" />
                             </button>
                         ) : (
                             <button 
                                onClick={() => handleDelete(img.id)}
                                className="p-2 hover:bg-red-500/20 text-red-400 rounded-lg transition-colors"
                                title="移除"
                                disabled={img.status === ProcessStatus.PROCESSING}
                             >
                                <Trash2 className="w-4 h-4" />
                             </button>
                         )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;

export interface LogoSettings {
  x: number; // Percentage 0-100
  y: number; // Percentage 0-100
  scale: number; // Percentage of base image width 1-100
  opacity: number; // 0-1
}

export enum ProcessStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR',
}

export interface ProcessedImage {
  id: string;
  originalFile: File;
  previewUrl: string; // URL for the original image
  resultUrl?: string; // URL for the processed image
  status: ProcessStatus;
  errorMessage?: string;
  progressValue?: number;
  progressMessage?: string;
}

export type ProcessingMode = 'remove-text' | 'add-logo' | 'both';

import React, { useRef, useState, useEffect } from 'react';
import { LogoSettings } from '../types';
import { Move, Maximize, Minimize, Eye, Upload, X, Check } from 'lucide-react';

interface LogoControlsProps {
  logoUrl: string | null;
  settings: LogoSettings;
  onSettingsChange: (settings: LogoSettings) => void;
  onLogoUpload: (file: File) => void;
  onLogoRemove: () => void;
  previewImageUrl: string | null;
}

export const LogoControls: React.FC<LogoControlsProps> = ({
  logoUrl,
  settings,
  onSettingsChange,
  onLogoUpload,
  onLogoRemove,
  previewImageUrl,
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // Unified drag handler that works for both small and large views
  // It uses e.currentTarget to calculate dimensions based on the element being interacted with
  const handleDrag = (e: React.MouseEvent | React.TouchEvent) => {
    e.preventDefault(); // Prevent scrolling on touch

    const container = e.currentTarget as HTMLDivElement;
    const rect = container.getBoundingClientRect();

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    // Calculate position relative to the container
    const x = Math.min(Math.max(0, clientX - rect.left), rect.width);
    const y = Math.min(Math.max(0, clientY - rect.top), rect.height);

    // Convert to percentages
    const xPercent = (x / rect.width) * 100;
    const yPercent = (y / rect.height) * 100;

    onSettingsChange({
      ...settings,
      x: xPercent,
      y: yPercent,
    });
  };

  const handleMouseDown = () => setIsDragging(true);

  // Global mouse up to stop dragging state
  useEffect(() => {
    const handleGlobalMouseUp = () => setIsDragging(false);
    window.addEventListener('mouseup', handleGlobalMouseUp);
    window.addEventListener('touchend', handleGlobalMouseUp);
    return () => {
      window.removeEventListener('mouseup', handleGlobalMouseUp);
      window.removeEventListener('touchend', handleGlobalMouseUp);
    };
  }, []);

  const handleContainerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (isDragging) {
      handleDrag(e);
    }
  };

  // Reusable visual component for the editor area
  const renderEditorArea = (isLargeMode: boolean) => (
    <div 
        className={`relative w-full ${isLargeMode ? 'h-full' : 'aspect-video'} bg-gray-900 rounded-lg overflow-hidden border border-gray-600 cursor-crosshair group select-none`}
        onMouseMove={handleContainerMove}
        onMouseDown={handleMouseDown}
        onTouchMove={handleContainerMove}
        onTouchStart={handleMouseDown}
        onMouseLeave={() => setIsDragging(false)}
    >
      {previewImageUrl ? (
         <img 
           src={previewImageUrl} 
           alt="Preview Background" 
           className="w-full h-full object-contain opacity-50 pointer-events-none"
           draggable={false}
         />
      ) : (
         <div className="w-full h-full flex items-center justify-center text-gray-600 text-sm pointer-events-none">
            无预览图片
         </div>
      )}

      {logoUrl && (
        <div
          style={{
            left: `${settings.x}%`,
            top: `${settings.y}%`,
            width: `${settings.scale}%`,
            opacity: settings.opacity,
            position: 'absolute',
            transform: 'translate(-0%, -0%)', // Anchor top-left
          }}
          className="pointer-events-none"
        >
          <img src={logoUrl} alt="Logo" className="w-full h-auto" draggable={false} />
          {/* Helper border */}
          <div className={`absolute inset-0 border-2 border-indigo-500 border-dashed transition-opacity ${isDragging ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`} />
        </div>
      )}

      {/* Grid lines for large mode precision */}
      {isLargeMode && (
          <div className="absolute inset-0 pointer-events-none opacity-10">
              <div className="w-full h-1/2 border-b border-white absolute top-0"></div>
              <div className="h-full w-1/2 border-r border-white absolute left-0"></div>
          </div>
      )}
    </div>
  );

  const renderSliders = () => (
    <div className="space-y-4 pt-2">
      <div className="space-y-1">
        <div className="flex justify-between text-xs text-gray-400">
          <span className="flex items-center gap-1"><Maximize className="w-3 h-3"/> 大小</span>
          <span>{Math.round(settings.scale)}%</span>
        </div>
        <input
          type="range"
          min="1"
          max="100"
          value={settings.scale}
          onChange={(e) => onSettingsChange({ ...settings, scale: Number(e.target.value) })}
          className="w-full h-2 bg-gray-600 rounded-lg appearance-none cursor-pointer accent-indigo-500"
        />
      </div>

      <div className="space-y-1">
        <div className="flex justify-between text-xs text-gray-400">
          <span className="flex items-center gap-1"><Eye className="w-3 h-3"/> 不透明度</span>
          <span>{Math.round(settings.opacity * 100)}%</span>
        </div>
        <input
          type="range"
          min="0"
          max="1"
          step="0.01"
          value={settings.opacity}
          onChange={(e) => onSettingsChange({ ...settings, opacity: Number(e.target.value) })}
          className="w-full h-2 bg-gray-600 rounded-lg appearance-none cursor-pointer accent-indigo-500"
        />
      </div>

       <div className="grid grid-cols-2 gap-2 text-xs">
            <div>
                 <label className="text-gray-500">水平位置 X (%)</label>
                 <input 
                    type="number" 
                    value={Math.round(settings.x)} 
                    onChange={(e) => onSettingsChange({ ...settings, x: Number(e.target.value) })}
                    className="w-full bg-gray-700 border border-gray-600 rounded px-2 py-1 text-white"
                 />
            </div>
            <div>
                 <label className="text-gray-500">垂直位置 Y (%)</label>
                 <input 
                    type="number" 
                    value={Math.round(settings.y)} 
                    onChange={(e) => onSettingsChange({ ...settings, y: Number(e.target.value) })}
                    className="w-full bg-gray-700 border border-gray-600 rounded px-2 py-1 text-white"
                 />
            </div>
       </div>
    </div>
  );

  return (
    <>
        <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 space-y-4">
        <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <Move className="w-5 h-5 text-indigo-400" />
            Logo 配置
        </h3>

        {/* Upload Area */}
        {!logoUrl ? (
            <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-gray-600 border-dashed rounded-lg cursor-pointer hover:bg-gray-700 transition-colors">
            <div className="flex flex-col items-center justify-center pt-5 pb-6">
                <Upload className="w-8 h-8 mb-2 text-gray-400" />
                <p className="text-sm text-gray-400">点击上传 Logo</p>
            </div>
            <input
                type="file"
                className="hidden"
                accept="image/*"
                onChange={(e) => {
                if (e.target.files?.[0]) onLogoUpload(e.target.files[0]);
                }}
            />
            </label>
        ) : (
            <div className="flex items-center justify-between bg-gray-700 p-2 rounded-lg">
            <span className="text-sm text-gray-300 truncate max-w-[150px]">Logo 已上传</span>
            <button
                onClick={onLogoRemove}
                className="text-red-400 hover:text-red-300 p-1 rounded-full hover:bg-gray-600"
            >
                <X className="w-4 h-4" />
            </button>
            </div>
        )}

        {/* Small Visual Editor (Sidebar) */}
        <div className="space-y-2 relative">
            <div className="flex justify-between items-center text-xs text-gray-400">
                <span>可视化定位</span>
                <button 
                    onClick={() => setIsExpanded(true)}
                    className="flex items-center gap-1 text-indigo-400 hover:text-indigo-300 transition-colors"
                >
                    <Maximize className="w-3 h-3" />
                    放大调整
                </button>
            </div>

            {/* Render the small editor */}
            {renderEditorArea(false)}
        </div>

        {/* Sliders (Sidebar) */}
        {logoUrl && renderSliders()}
        </div>

        {/* Expanded Modal */}
        {isExpanded && (
            <div className="fixed inset-0 z-50 bg-black/95 flex items-center justify-center p-4 md:p-10 animate-fade-in">
                <div className="bg-gray-900 w-full max-w-6xl h-full md:h-[90vh] rounded-2xl border border-gray-700 shadow-2xl flex flex-col md:flex-row overflow-hidden">

                    {/* Main Canvas Area */}
                    <div className="flex-1 relative bg-gray-950 p-4 flex flex-col">
                        <div className="flex justify-between items-center mb-4 md:hidden">
                            <h3 className="text-white font-bold">精细调整模式</h3>
                            <button onClick={() => setIsExpanded(false)} className="text-gray-400"><X /></button>
                        </div>

                        <div className="flex-1 relative rounded-xl overflow-hidden border border-gray-800">
                             {/* Render the large editor */}
                            {renderEditorArea(true)}
                        </div>

                        <div className="text-center text-gray-500 text-xs mt-2">
                             拖动 Logo 进行精细定位
                        </div>
                    </div>

                    {/* Sidebar in Modal */}
                    <div className="w-full md:w-80 bg-gray-800 p-6 flex flex-col border-l border-gray-700 overflow-y-auto">
                        <div className="flex justify-between items-center mb-8">
                            <h3 className="text-xl font-bold text-white flex items-center gap-2">
                                <Move className="w-6 h-6 text-indigo-400" />
                                调整参数
                            </h3>
                            <button 
                                onClick={() => setIsExpanded(false)}
                                className="p-2 hover:bg-gray-700 rounded-lg transition-colors hidden md:block"
                            >
                                <Minimize className="w-5 h-5 text-gray-400" />
                            </button>
                        </div>

                        {logoUrl && renderSliders()}

                        <div className="mt-auto pt-8">
                            <button
                                onClick={() => setIsExpanded(false)}
                                className="w-full py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-medium flex items-center justify-center gap-2"
                            >
                                <Check className="w-5 h-5" />
                                完成调整
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { LogoSettings } from '../types';
import { Move, Maximize, Minimize, Eye, Upload, X, Check } from 'lucide-react';

interface LogoControlsProps {
  logoUrl: string | null;
  settings: LogoSettings;
  onSettingsChange: (settings: LogoSettings) => void;
  onLogoUpload: (file: File) => void;
  onLogoRemove: () => void;
  previewImageUrl: string | null;
}

export const LogoControls: React.FC<LogoControlsProps> = ({
  logoUrl,
  settings,
  onSettingsChange,
  onLogoUpload,
  onLogoRemove,
  previewImageUrl,
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [imageAspectRatio, setImageAspectRatio] = useState(16 / 9);

  // Update aspect ratio when image changes
  useEffect(() => {
    if (!previewImageUrl) return;
    const img = new Image();
    img.onload = () => {
        if (img.naturalHeight > 0) {
            setImageAspectRatio(img.naturalWidth / img.naturalHeight);
        }
    };
    img.src = previewImageUrl;
  }, [previewImageUrl]);

  // Unified drag handler that works for both small and large views
  // It uses e.currentTarget to calculate dimensions based on the element being interacted with
  const handleDrag = (e: React.MouseEvent | React.TouchEvent) => {
    e.preventDefault(); // Prevent scrolling on touch

    const container = e.currentTarget as HTMLDivElement;
    const rect = container.getBoundingClientRect();

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    // Calculate position relative to the container
    const x = Math.min(Math.max(0, clientX - rect.left), rect.width);
    const y = Math.min(Math.max(0, clientY - rect.top), rect.height);

    // Convert to percentages
    const xPercent = (x / rect.width) * 100;
    const yPercent = (y / rect.height) * 100;

    onSettingsChange({
      ...settings,
      x: xPercent,
      y: yPercent,
    });
  };

  const handleMouseDown = () => setIsDragging(true);

  // Global mouse up to stop dragging state
  useEffect(() => {
    const handleGlobalMouseUp = () => setIsDragging(false);
    window.addEventListener('mouseup', handleGlobalMouseUp);
    window.addEventListener('touchend', handleGlobalMouseUp);
    return () => {
      window.removeEventListener('mouseup', handleGlobalMouseUp);
      window.removeEventListener('touchend', handleGlobalMouseUp);
    };
  }, []);

  const handleContainerMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (isDragging) {
      handleDrag(e);
    }
  };

  // Reusable visual component for the editor area
  // We use a "Flex Center" approach for the outer container
  // And a "Intrinsic Ratio" approach for the inner stage
  const renderEditorArea = (isLargeMode: boolean) => (
    <div 
        className={`${isLargeMode ? 'w-full h-full' : 'w-full h-48'} bg-gray-900 rounded-lg overflow-hidden border border-gray-600 flex items-center justify-center select-none`}
    >
        {previewImageUrl ? (
             <div
                className="relative shadow-2xl cursor-crosshair group"
                style={{
                    aspectRatio: imageAspectRatio,
                    maxWidth: '100%',
                    maxHeight: '100%'
                }}
                onMouseMove={handleContainerMove}
                onMouseDown={handleMouseDown}
                onTouchMove={handleContainerMove}
                onTouchStart={handleMouseDown}
                onMouseLeave={() => setIsDragging(false)}
             >
                <img 
                    src={previewImageUrl} 
                    alt="Preview Background" 
                    className="w-full h-full object-cover block pointer-events-none"
                    draggable={false}
                />

                {logoUrl && (
                    <div
                    style={{
                        left: `${settings.x}%`,
                        top: `${settings.y}%`,
                        width: `${settings.scale}%`,
                        opacity: settings.opacity,
                        position: 'absolute',
                        transform: 'translate(-0%, -0%)', // Anchor top-left
                    }}
                    className="pointer-events-none"
                    >
                    <img src={logoUrl} alt="Logo" className="w-full h-auto block" draggable={false} />
                    {/* Helper border */}
                    <div className={`absolute inset-0 border-2 border-indigo-500 border-dashed transition-opacity ${isDragging ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`} />
                    </div>
                )}

                {/* Grid lines for large mode precision */}
                {isLargeMode && (
                    <div className="absolute inset-0 pointer-events-none opacity-20">
                        <div className="w-full h-1/2 border-b border-white absolute top-0"></div>
                        <div className="h-full w-1/2 border-r border-white absolute left-0"></div>
                    </div>
                )}
             </div>
        ) : (
            <div className="text-gray-600 text-sm pointer-events-none">
                无预览图片
            </div>
        )}
    </div>
  );

  const renderSliders = () => (
    <div className="space-y-4 pt-2">
      <div className="space-y-1">
        <div className="flex justify-between text-xs text-gray-400">
          <span className="flex items-center gap-1"><Maximize className="w-3 h-3"/> 大小</span>
          <span>{Math.round(settings.scale)}%</span>
        </div>
        <input
          type="range"
          min="1"
          max="100"
          value={settings.scale}
          onChange={(e) => onSettingsChange({ ...settings, scale: Number(e.target.value) })}
          className="w-full h-2 bg-gray-600 rounded-lg appearance-none cursor-pointer accent-indigo-500"
        />
      </div>

      <div className="space-y-1">
        <div className="flex justify-between text-xs text-gray-400">
          <span className="flex items-center gap-1"><Eye className="w-3 h-3"/> 不透明度</span>
          <span>{Math.round(settings.opacity * 100)}%</span>
        </div>
        <input
          type="range"
          min="0"
          max="1"
          step="0.01"
          value={settings.opacity}
          onChange={(e) => onSettingsChange({ ...settings, opacity: Number(e.target.value) })}
          className="w-full h-2 bg-gray-600 rounded-lg appearance-none cursor-pointer accent-indigo-500"
        />
      </div>

       <div className="grid grid-cols-2 gap-2 text-xs">
            <div>
                 <label className="text-gray-500">水平位置 X (%)</label>
                 <input 
                    type="number" 
                    value={Math.round(settings.x)} 
                    onChange={(e) => onSettingsChange({ ...settings, x: Number(e.target.value) })}
                    className="w-full bg-gray-700 border border-gray-600 rounded px-2 py-1 text-white"
                 />
            </div>
            <div>
                 <label className="text-gray-500">垂直位置 Y (%)</label>
                 <input 
                    type="number" 
                    value={Math.round(settings.y)} 
                    onChange={(e) => onSettingsChange({ ...settings, y: Number(e.target.value) })}
                    className="w-full bg-gray-700 border border-gray-600 rounded px-2 py-1 text-white"
                 />
            </div>
       </div>
    </div>
  );

  return (
    <>
        <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 space-y-4">
        <h3 className="text-lg font-semibold text-white flex items-center gap-2">
            <Move className="w-5 h-5 text-indigo-400" />
            Logo 配置
        </h3>

        {/* Upload Area */}
        {!logoUrl ? (
            <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-gray-600 border-dashed rounded-lg cursor-pointer hover:bg-gray-700 transition-colors">
            <div className="flex flex-col items-center justify-center pt-5 pb-6">
                <Upload className="w-8 h-8 mb-2 text-gray-400" />
                <p className="text-sm text-gray-400">点击上传 Logo</p>
            </div>
            <input
                type="file"
                className="hidden"
                accept="image/*"
                onChange={(e) => {
                if (e.target.files?.[0]) onLogoUpload(e.target.files[0]);
                }}
            />
            </label>
        ) : (
            <div className="flex items-center justify-between bg-gray-700 p-2 rounded-lg">
            <span className="text-sm text-gray-300 truncate max-w-[150px]">Logo 已上传</span>
            <button
                onClick={onLogoRemove}
                className="text-red-400 hover:text-red-300 p-1 rounded-full hover:bg-gray-600"
            >
                <X className="w-4 h-4" />
            </button>
            </div>
        )}

        {/* Small Visual Editor (Sidebar) */}
        <div className="space-y-2 relative">
            <div className="flex justify-between items-center text-xs text-gray-400">
                <span>可视化定位</span>
                <button 
                    onClick={() => setIsExpanded(true)}
                    className="flex items-center gap-1 text-indigo-400 hover:text-indigo-300 transition-colors"
                >
                    <Maximize className="w-3 h-3" />
                    放大调整
                </button>
            </div>

            {/* Render the small editor */}
            {renderEditorArea(false)}
        </div>

        {/* Sliders (Sidebar) */}
        {logoUrl && renderSliders()}
        </div>

        {/* Expanded Modal */}
        {isExpanded && (
            <div className="fixed inset-0 z-50 bg-black/95 flex items-center justify-center p-4 md:p-10 animate-fade-in">
                <div className="bg-gray-900 w-full max-w-6xl h-full md:h-[90vh] rounded-2xl border border-gray-700 shadow-2xl flex flex-col md:flex-row overflow-hidden">

                    {/* Main Canvas Area */}
                    <div className="flex-1 relative bg-gray-950 p-4 flex flex-col">
                        <div className="flex justify-between items-center mb-4 md:hidden">
                            <h3 className="text-white font-bold">精细调整模式</h3>
                            <button onClick={() => setIsExpanded(false)} className="text-gray-400"><X /></button>
                        </div>

                        <div className="flex-1 relative rounded-xl overflow-hidden border border-gray-800 flex items-center justify-center">
                             {/* Render the large editor */}
                            {renderEditorArea(true)}
                        </div>

                        <div className="text-center text-gray-500 text-xs mt-2">
                             拖动 Logo 进行精细定位
                        </div>
                    </div>

                    {/* Sidebar in Modal */}
                    <div className="w-full md:w-80 bg-gray-800 p-6 flex flex-col border-l border-gray-700 overflow-y-auto">
                        <div className="flex justify-between items-center mb-8">
                            <h3 className="text-xl font-bold text-white flex items-center gap-2">
                                <Move className="w-6 h-6 text-indigo-400" />
                                调整参数
                            </h3>
                            <button 
                                onClick={() => setIsExpanded(false)}
                                className="p-2 hover:bg-gray-700 rounded-lg transition-colors hidden md:block"
                            >
                                <Minimize className="w-5 h-5 text-gray-400" />
                            </button>
                        </div>

                        {logoUrl && renderSliders()}

                        <div className="mt-auto pt-8">
                            <button
                                onClick={() => setIsExpanded(false)}
                                className="w-full py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-medium flex items-center justify-center gap-2"
                            >
                                <Check className="w-5 h-5" />
                                完成调整
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </>
  );
};

import React, { useState, useCallback, useMemo } from 'react';
import { Upload, Image as ImageIcon, Wand2, Download, Trash2, Layers, AlertCircle, Play, Stamp, Package } from 'lucide-react';
import JSZip from 'jszip';
import { ProcessedImage, ProcessStatus, LogoSettings, ProcessingMode } from './types';
import { removeTextFromImage } from './services/geminiService';
import { applyLogoToImage, getImageDimensions } from './services/canvasService';
import { LogoControls } from './components/LogoControls';

const DEFAULT_LOGO_SETTINGS: LogoSettings = {
  x: 5,
  y: 5,
  scale: 20,
  opacity: 1,
};

function App() {
  const [images, setImages] = useState<ProcessedImage[]>([]);
  const [logoUrl, setLogoUrl] = useState<string | null>(null);
  const [logoSettings, setLogoSettings] = useState<LogoSettings>(DEFAULT_LOGO_SETTINGS);
  const [mode, setMode] = useState<ProcessingMode>('remove-text');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [isDraggingOver, setIsDraggingOver] = useState(false);

  // Helper to create a unique ID
  const generateId = () => Math.random().toString(36).substr(2, 9);

  // Unified File Handler
  const handleFiles = (files: FileList | File[]) => {
    const validFiles = Array.from(files).filter(file => file.type.startsWith('image/'));

    if (validFiles.length > 0) {
      const newImages: ProcessedImage[] = validFiles.map((file) => ({
        id: generateId(),
        originalFile: file,
        previewUrl: URL.createObjectURL(file),
        status: ProcessStatus.IDLE,
      }));
      setImages((prev) => [...prev, ...newImages]);
    }
  };

  // Handle Main Image Upload (Input)
  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      handleFiles(e.target.files);
      // Reset input to allow selecting same file again
      e.target.value = ''; 
    }
  };

  // Drag and Drop Handlers
  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!isDraggingOver) setIsDraggingOver(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Only set to false if we are leaving the main container
    if (e.currentTarget.contains(e.relatedTarget as Node)) return;
    setIsDraggingOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingOver(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFiles(e.dataTransfer.files);
    }
  };

  // Handle Logo Upload
  const handleLogoUpload = (file: File) => {
    const url = URL.createObjectURL(file);
    setLogoUrl(url);
  };

  // Handle Individual Delete
  const handleDelete = (id: string) => {
    setImages((prev) => {
      const target = prev.find((img) => img.id === id);
      if (target) {
        URL.revokeObjectURL(target.previewUrl);
        if (target.resultUrl) URL.revokeObjectURL(target.resultUrl);
      }
      return prev.filter((img) => img.id !== id);
    });
  };

  // Main Processing Logic
  const processBatch = async () => {
    if (images.length === 0) return;
    setIsProcessing(true);

    const processedImages = [...images];

    for (let i = 0; i < processedImages.length; i++) {
      const img = processedImages[i];
      if (img.status === ProcessStatus.COMPLETED) continue; // Skip already done

      // Update status to processing
      processedImages[i] = { 
        ...img, 
        status: ProcessStatus.PROCESSING, 
        errorMessage: undefined,
        progressValue: 0,
        progressMessage: '准备处理...'
      };
      setImages([...processedImages]);

      try {
        // Get Original Dimensions to ensure output matches
        const originalDims = await getImageDimensions(img.previewUrl);

        let currentResultUrl = img.previewUrl;

        // Step 1: Remove Text (AI)
        if (mode === 'remove-text' || mode === 'both') {
          processedImages[i].progressMessage = 'AI 正在智能去字...';
          processedImages[i].progressValue = 30;
          setImages([...processedImages]);

          try {
            const aiResultBase64 = await removeTextFromImage(img.originalFile);
            currentResultUrl = aiResultBase64;
          } catch (err: any) {
            throw new Error(`AI 处理失败: ${err.message || '未知错误'}`);
          }
        }

        // Step 2: Ensure Dimensions & Add Logo (Canvas)
        // We always run this step if:
        // 1. We need to add a logo
        // 2. OR we just ran AI (which might have resized the image) and need to restore dimensions
        const shouldAddLogo = (mode === 'add-logo' || mode === 'both') && !!logoUrl;

        if (shouldAddLogo || mode === 'remove-text' || mode === 'both') {
           processedImages[i].progressMessage = shouldAddLogo ? '正在合成水印...' : '正在优化尺寸...';
           processedImages[i].progressValue = shouldAddLogo ? 60 : 80;
           setImages([...processedImages]);

           try {
              currentResultUrl = await applyLogoToImage(
                  currentResultUrl, 
                  shouldAddLogo ? logoUrl : null, 
                  logoSettings,
                  originalDims
              );
           } catch (err: any) {
              throw new Error(`图像合成失败: ${err.message}`);
           }
        }

        // Finalize
        processedImages[i] = {
          ...img,
          resultUrl: currentResultUrl,
          status: ProcessStatus.COMPLETED,
          progressValue: 100,
          progressMessage: '处理完成'
        };
      } catch (error: any) {
        processedImages[i] = {
          ...img,
          status: ProcessStatus.ERROR,
          errorMessage: error.message,
          progressValue: 0,
          progressMessage: '处理出错'
        };
      }

      // Update state after each image to show progress
      setImages([...processedImages]);
    }

    setIsProcessing(false);
  };

  // Download Handler
  const downloadImage = (img: ProcessedImage) => {
    if (!img.resultUrl) return;
    const link = document.createElement('a');
    link.href = img.resultUrl;
    link.download = `processed_${img.originalFile.name.split('.')[0]}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Download All Handler
  const handleDownloadAll = async () => {
    const completedImages = images.filter(img => img.status === ProcessStatus.COMPLETED && img.resultUrl);
    if (completedImages.length === 0) return;

    setIsZipping(true);
    try {
      const zip = new JSZip();

      const promises = completedImages.map(async (img) => {
        if (!img.resultUrl) return;
        const response = await fetch(img.resultUrl);
        const blob = await response.blob();

        // Determine extension
        let ext = 'png';
        if (blob.type === 'image/jpeg') ext = 'jpg';
        else if (blob.type === 'image/webp') ext = 'webp';

        const originalName = img.originalFile.name;
        const nameWithoutExt = originalName.substring(0, originalName.lastIndexOf('.')) || originalName;

        zip.file(`processed_${nameWithoutExt}.${ext}`, blob);
      });

      await Promise.all(promises);

      const content = await zip.generateAsync({ type: "blob" });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `cleanslate_batch_${new Date().getTime()}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (error) {
      console.error("Zip generation failed", error);
      alert("打包下载失败，请重试");
    } finally {
      setIsZipping(false);
    }
  };

  const clearAll = () => {
    images.forEach(img => {
        URL.revokeObjectURL(img.previewUrl);
        if(img.resultUrl) URL.revokeObjectURL(img.resultUrl);
    });
    setImages([]);
  };

  // Determines the image to show in the logo editor preview
  const firstPreviewImage = useMemo(() => {
    return images.length > 0 ? images[0].previewUrl : null;
  }, [images]);

  const hasCompletedImages = images.some(img => img.status === ProcessStatus.COMPLETED);

  return (
    <div className="flex h-full text-gray-100">
      {/* Sidebar Controls */}
      <aside className="w-80 flex-shrink-0 bg-gray-900 border-r border-gray-800 flex flex-col p-4 space-y-6 overflow-y-auto">
        <div>
          <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text text-transparent flex items-center gap-2">
            <Layers className="w-6 h-6 text-indigo-400" />
            CleanSlate AI
          </h1>
          <p className="text-xs text-gray-500 mt-1">批量去字 & 品牌水印</p>
        </div>

        {/* Mode Selector */}
        <div className="space-y-3">
          <label className="text-sm font-semibold text-gray-400 uppercase tracking-wider">操作模式</label>
          <div className="grid grid-cols-1 gap-2">
            <button
              onClick={() => setMode('remove-text')}
              className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
                mode === 'remove-text'
                  ? 'bg-indigo-900/40 border-indigo-500 text-white'
                  : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'
              }`}
            >
              <Wand2 className="w-5 h-5" />
              <div className="text-left">
                <div className="font-medium">去除文字</div>
                <div className="text-xs opacity-70">AI 智能清除</div>
              </div>
            </button>

            <button
              onClick={() => setMode('add-logo')}
              className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
                mode === 'add-logo'
                  ? 'bg-indigo-900/40 border-indigo-500 text-white'
                  : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'
              }`}
            >
              <Stamp className="w-5 h-5" />
              <div className="text-left">
                <div className="font-medium">添加 Logo</div>
                <div className="text-xs opacity-70">水印布局</div>
              </div>
            </button>

            <button
              onClick={() => setMode('both')}
              className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
                mode === 'both'
                  ? 'bg-indigo-900/40 border-indigo-500 text-white'
                  : 'bg-gray-800 border-gray-700 text-gray-400 hover:bg-gray-750'
              }`}
            >
              <Layers className="w-5 h-5" />
              <div className="text-left">
                <div className="font-medium">去字 & 水印</div>
                <div className="text-xs opacity-70">先去字，后加 Logo</div>
              </div>
            </button>
          </div>
        </div>

        {/* Logo Controls (Only if needed) */}
        {(mode === 'add-logo' || mode === 'both') && (
          <LogoControls
            logoUrl={logoUrl}
            settings={logoSettings}
            onSettingsChange={setLogoSettings}
            onLogoUpload={handleLogoUpload}
            onLogoRemove={() => setLogoUrl(null)}
            previewImageUrl={firstPreviewImage}
          />
        )}

        {/* Action Button */}
        <div className="pt-4 mt-auto">
          <button
            onClick={processBatch}
            disabled={isProcessing || images.length === 0}
            className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-2 transition-all ${
              isProcessing || images.length === 0
                ? 'bg-gray-700 text-gray-500 cursor-not-allowed'
                : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white transform hover:scale-[1.02]'
            }`}
          >
            {isProcessing ? (
              <>
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                处理中...
              </>
            ) : (
              <>
                <Play className="w-5 h-5 fill-current" />
                开始处理
              </>
            )}
          </button>
        </div>
      </aside>

      {/* Main Content Area - Drag Target */}
      <main 
        className="flex-1 flex flex-col bg-gray-950 overflow-hidden relative"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {/* Drag Overlay */}
        {isDraggingOver && (
            <div className="absolute inset-0 z-50 bg-indigo-500/10 backdrop-blur-sm border-4 border-dashed border-indigo-500 m-4 rounded-3xl flex flex-col items-center justify-center pointer-events-none animate-in fade-in duration-200">
                <Upload className="w-16 h-16 text-indigo-400 mb-4 animate-bounce" />
                <h2 className="text-3xl font-bold text-indigo-200">释放以添加图片</h2>
                <p className="text-indigo-300 mt-2">支持批量导入</p>
            </div>
        )}

        {/* Header / Stats */}
        <header className="h-16 border-b border-gray-800 flex items-center justify-between px-6 bg-gray-900/50 backdrop-blur z-20">
          <div className="flex items-center gap-4">
             <span className="text-gray-400 text-sm">
                已加载 {images.length} 张图片
             </span>
             {hasCompletedImages && (
                <span className="text-green-400 text-sm flex items-center gap-1">
                   <div className="w-2 h-2 rounded-full bg-green-500"></div>
                   准备下载
                </span>
             )}
          </div>
          <div className="flex gap-2">
             {hasCompletedImages && (
                <button 
                    onClick={handleDownloadAll}
                    disabled={isZipping}
                    className="px-3 py-1.5 text-sm bg-indigo-600 hover:bg-indigo-500 disabled:bg-indigo-800 disabled:text-gray-400 text-white rounded-lg transition-colors flex items-center gap-2 shadow-lg shadow-indigo-900/20"
                >
                    {isZipping ? (
                        <>
                           <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                           打包中...
                        </>
                    ) : (
                        <>
                           <Package className="w-4 h-4" /> 批量下载
                        </>
                    )}
                </button>
             )}

             <button 
                onClick={clearAll}
                className="px-3 py-1.5 text-sm text-red-400 hover:bg-red-900/20 rounded-lg transition-colors flex items-center gap-2"
                disabled={isProcessing}
             >
                <Trash2 className="w-4 h-4"/> 清空所有
             </button>
             <label className="cursor-pointer px-4 py-1.5 text-sm bg-gray-700 hover:bg-gray-600 text-white rounded-lg transition-colors flex items-center gap-2">
                <Upload className="w-4 h-4"/> 添加图片
                <input type="file" multiple accept="image/*" onChange={handleImageUpload} className="hidden" />
             </label>
          </div>
        </header>

        {/* Image Grid */}
        <div className="flex-1 overflow-y-auto p-6 z-10">
          {images.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-500 border-2 border-dashed border-gray-800 rounded-3xl bg-gray-900/30 m-4">
              <div className="p-8 bg-gray-900 rounded-full mb-6">
                <ImageIcon className="w-12 h-12 text-indigo-500" />
              </div>
              <h2 className="text-2xl font-semibold text-gray-300 mb-2">拖放图片到这里</h2>
              <p className="max-w-md text-center text-gray-500">
                上传多张图片以批量去除文字或添加您的品牌水印。
              </p>
              <label className="mt-8 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl cursor-pointer font-medium transition-transform hover:scale-105">
                选择文件
                <input type="file" multiple accept="image/*" onChange={handleImageUpload} className="hidden" />
              </label>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
              {images.map((img) => (
                <div
                  key={img.id}
                  className="group relative bg-gray-800 rounded-xl overflow-hidden shadow-xl border border-gray-700 hover:border-indigo-500/50 transition-all"
                >
                  {/* Image Preview */}
                  <div className="aspect-video relative bg-gray-900 flex items-center justify-center overflow-hidden">
                    {img.status === ProcessStatus.COMPLETED && img.resultUrl ? (
                         // Compare View
                         <>
                            <img src={img.resultUrl} className="w-full h-full object-contain" alt="Processed" />
                            <div className="absolute top-2 left-2 bg-green-500/90 text-white text-[10px] font-bold px-2 py-0.5 rounded shadow-sm">
                                已处理
                            </div>
                         </>
                    ) : (
                         <img src={img.previewUrl} className={`w-full h-full object-contain ${img.status === ProcessStatus.PROCESSING ? 'opacity-50' : ''}`} alt="Original" />
                    )}

                    {/* Status Overlays */}
                    {img.status === ProcessStatus.PROCESSING && (
                        <div className="absolute inset-0 bg-gray-900/70 backdrop-blur-sm flex flex-col items-center justify-center z-10">
                            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-3"></div>
                            <div className="w-48 bg-gray-700 rounded-full h-2 mb-2 overflow-hidden">
                                <div 
                                   className="bg-indigo-500 h-full transition-all duration-300 ease-out"
                                   style={{ width: `${img.progressValue || 0}%` }}
                                ></div>
                            </div>
                            <span className="text-white text-sm font-medium animate-pulse">{img.progressMessage || '处理中...'}</span>
                        </div>
                    )}

                    {img.status === ProcessStatus.ERROR && (
                        <div className="absolute inset-0 bg-red-900/60 flex flex-col items-center justify-center p-4 text-center">
                            <AlertCircle className="w-8 h-8 text-red-200 mb-2" />
                            <span className="text-red-200 text-xs font-medium">{img.errorMessage}</span>
                        </div>
                    )}
                  </div>

                  {/* Footer Actions */}
                  <div className="p-3 bg-gray-800 flex items-center justify-between border-t border-gray-700">
                    <div className="truncate text-xs text-gray-400 max-w-[150px]">
                        {img.originalFile.name}
                    </div>
                    <div className="flex gap-2">
                         {img.status === ProcessStatus.COMPLETED ? (
                             <button 
                                onClick={() => downloadImage(img)}
                                className="p-2 hover:bg-green-500/20 text-green-400 rounded-lg transition-colors"
                                title="下载"
                             >
                                <Download className="w-4 h-4" />
                             </button>
                         ) : (
                             <button 
                                onClick={() => handleDelete(img.id)}
                                className="p-2 hover:bg-red-500/20 text-red-400 rounded-lg transition-colors"
                                title="移除"
                                disabled={img.status === ProcessStatus.PROCESSING}
                             >
                                <Trash2 className="w-4 h-4" />
                             </button>
                         )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;

import { GoogleGenAI } from "@google/genai";

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove Data URI prefix (e.g. "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const removeTextFromImage = async (file: File): Promise<string> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("未找到 API Key。请设置 API_KEY 环境变量。");
  }

  const ai = new GoogleGenAI({ apiKey });
  const base64Data = await fileToBase64(file);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: file.type || 'image/png',
            },
          },
          {
            text: "Edit this image. Remove all text from the image. If the image has a white background and contains any colored borders or frames, remove them to leave a clean white background.",
          },
        ],
      },
    });

    // Extract the image from the response
    if (response.candidates && response.candidates.length > 0) {
      const content = response.candidates[0].content;
      if (content && content.parts) {
        for (const part of content.parts) {
          if (part.inlineData && part.inlineData.data) {
            return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
          }
        }

        // If no image found, check for text response (e.g. refusal or error message)
        const textPart = content.parts.find(p => p.text);
        if (textPart && textPart.text) {
          throw new Error(`模型响应了文本而非图片: ${textPart.text}`);
        }
      }
    }

    throw new Error("Gemini 未返回图像数据。");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

